func (t Channel) Discriminator() (string, error) {
	var discriminator struct {
		Discriminator string `json:"type"`
	}
	err := json.Unmarshal(t.union, &discriminator)
	return discriminator.Discriminator, err
}

func (t Channel) ValueByDiscriminator() (interface{}, error) {
	discriminator, err := t.Discriminator()
	if err != nil {
		return nil, err
	}
	switch discriminator {
	case "ADC":
		return t.AsADCChannel()
	case "DAC":
		return t.AsDACChannel()
	case "GPIOIN":
		return t.AsGPIOINChannel()
	case "GPIOOUT":
		return t.AsGPIOOUTChannel()
	case "MQTT":
		return t.AsMQTTChannel()
	case "PWM":
		return t.AsPWMChannel()
	case "UART":
		return t.AsUARTChannel()
	default:
		return nil, errors.New("unknown discriminator value: " + discriminator)
	}
}

