func (t Node) Discriminator() (string, error) {
	var discriminator struct {
		Discriminator string `json:"type"`
	}
	err := json.Unmarshal(t.union, &discriminator)
	return discriminator.Discriminator, err
}

func (t Node) ValueByDiscriminator() (interface{}, error) {
	discriminator, err := t.Discriminator()
	if err != nil {
		return nil, err
	}
	switch discriminator {
	case "Agent":
		return t.AsAgentNode()
	case "Alarm":
		return t.AsAlarmNode()
	case "Delay":
		return t.AsDelayNode()
	case "FunctionCall":
		return t.AsFunctionCallNode()
	case "If":
		return t.AsIfNode()
	case "MqttPublish":
		return t.AsMqttPublishNode()
	case "OnFunctionCall":
		return t.AsOnFunctionCallNode()
	case "OnMqttMessage":
		return t.AsOnMqttMessageNode()
	case "OnPinEdge":
		return t.AsOnPinEdgeNode()
	case "OnSerialReceive":
		return t.AsOnSerialReceiveNode()
	case "OnStartup":
		return t.AsOnStartupNode()
	case "OnThreshold":
		return t.AsOnThresholdNode()
	case "ReadPin":
		return t.AsReadPinNode()
	case "Retriever":
		return t.AsRetrieverNode()
	case "SerialRead":
		return t.AsSerialReadNode()
	case "SerialWrite":
		return t.AsSerialWriteNode()
	case "SetVariable":
		return t.AsSetVariableNode()
	case "Ticker":
		return t.AsTickerNode()
	case "WebFetch":
		return t.AsWebFetchNode()
	case "WebSearchTool":
		return t.AsWebSearchToolNode()
	case "WritePin":
		return t.AsWritePinNode()
	default:
		return nil, errors.New("unknown discriminator value: " + discriminator)
	}
}

